	@Test
	void roundTripsJoinFilterAndScalarTreeWithoutRetainingSourceNodes() {
		StatementPattern left = new StatementPattern(Var.of("person"),
				Var.of("namePredicate", VF.createIRI("urn:name")), Var.of("name"));
		StatementPattern right = new StatementPattern(Var.of("person"),
				Var.of("agePredicate", VF.createIRI("urn:age")), Var.of("age"));
		TupleExpr source = new Filter(new Join(left, right),
				new Compare(Var.of("age"), new ValueConstant(VF.createLiteral(18)), Compare.CompareOp.GE));

		PackedQuery packed = PackedQueryCodec.encode(source);
		TupleExpr materialized = PackedPlanMaterializer.materialize(packed, packed.rootRelId());

		assertEquals(source, materialized);
		assertEquals(4, packed.relationCount());
		assertEquals(PackedRelOp.FILTER, packed.relOperator(packed.rootRelId()));
		for (int objectId = 1; objectId <= packed.objectCount(); objectId++) {
			assertFalse(packed.objectValue(objectId) instanceof QueryModelNode);
		}
	}

	@Test
	void roundTripsCommonTupleAndScalarOperatorFamilies() {
		StatementPattern names = new StatementPattern(Var.of("person"),
				Var.of("namePredicate", VF.createIRI("urn:name")), Var.of("name"));
		StatementPattern ages = new StatementPattern(Var.of("person"),
				Var.of("agePredicate", VF.createIRI("urn:age")), Var.of("age"));
		Compare adult = new Compare(
				new MathExpr(Var.of("age"), new ValueConstant(VF.createLiteral(1)), MathExpr.MathOp.PLUS),
				new ValueConstant(VF.createLiteral(18)), Compare.CompareOp.GE);
		Regex namedA = new Regex(new Str(Var.of("name")), new ValueConstant(VF.createLiteral("^A")),
				new ValueConstant(VF.createLiteral("i")));
		And condition = new And(adult,
				new Or(new SameTerm(Var.of("person"), Var.of("person")), new Not(namedA)));

		TupleExpr binary = new Lateral(
				new Intersection(new Union(new Filter(names, condition), new EmptySet()),
						new Difference(new LeftJoin(ages, new SingletonSet(), new Bound(Var.of("age"))),
								new EmptySet())),
				new SingletonSet(), Set.of("person"));
		Extension extension = new Extension(binary,
				new ExtensionElem(new If(new Bound(Var.of("name")),
						new FunctionCall("urn:function", new Str(Var.of("name"))),
						new ValueConstant(VF.createLiteral("unknown"))), "displayName"));
		Order order = new Order(extension, new OrderElem(Var.of("displayName"), false));
		Projection projection = new Projection(order,
				new ProjectionElemList(new ProjectionElem("person", "selectedPerson"),
						new ProjectionElem("displayName")),
				false);
		projection.setProjectionContext(Var.of("projectionContext"));
		MultiProjection multiProjection = new MultiProjection(projection,
				List.of(new ProjectionElemList(new ProjectionElem("selectedPerson")),
						new ProjectionElemList(new ProjectionElem("displayName"))));
		TupleExpr source = new QueryRoot(new DescribeOperator(new Slice(
				new Reduced(new Distinct(new MaterializeTupleExpr(multiProjection))), 2, 5)));

		PackedQuery packed = PackedQueryCodec.encode(source);
		TupleExpr materialized = PackedPlanMaterializer.materialize(packed, packed.rootRelId());

		assertEquals(source, materialized);
	}

