	@Test
	void roundTripsGroupAndAggregateOperatorFamilies() {
		GroupConcat concat = new GroupConcat(Var.of("label"), true);
		concat.setSeparator(new ValueConstant(VF.createLiteral(" | ")));
		Group source = new Group(
				new StatementPattern(Var.of("person"), Var.of("scorePredicate", VF.createIRI("urn:score")),
						Var.of("score")),
				List.of("person"),
				List.of(new GroupElem("count", new Count(null, true)),
						new GroupElem("average", new Avg(Var.of("score"), true)),
						new GroupElem("sum", new Sum(Var.of("score"), false)),
						new GroupElem("minimum", new Min(Var.of("score"), false)),
						new GroupElem("maximum", new Max(Var.of("score"), true)),
						new GroupElem("sample", new Sample(Var.of("score"), false)),
						new GroupElem("labels", concat),
						new GroupElem("custom", new AggregateFunctionCall(
								List.of(Var.of("score"), new ValueConstant(VF.createLiteral(2))),
								"urn:aggregate", true))));

		PackedQuery packed = PackedQueryCodec.encode(source);
		TupleExpr materialized = PackedPlanMaterializer.materialize(packed, packed.rootRelId());

		assertEquals(source, materialized);
		Group materializedGroup = (Group) materialized;
		GroupConcat materializedConcat = (GroupConcat) materializedGroup.getGroupElements().get(6).getOperator();
		assertEquals(concat.getSeparator(), materializedConcat.getSeparator());
	}

	@Test
	void roundTripsValuesServiceAndTupleFunctionOperators() {
		MapBindingSet first = new MapBindingSet(2);
		first.setBinding("person", VF.createIRI("urn:person:1"));
		first.setBinding("score", VF.createLiteral(10));
		MapBindingSet second = new MapBindingSet(1);
		second.setBinding("person", VF.createIRI("urn:person:2"));
		BindingSetAssignment values = new BindingSetAssignment();
		values.setBindingNames(new LinkedHashSet<>(List.of("person", "score")));
		values.setBindingSets(List.of(first, second));

		LinkedHashMap<String, String> prefixes = new LinkedHashMap<>();
		prefixes.put("ex", "https://example.com/");
		prefixes.put("schema", "https://schema.org/");
		Service service = new Service(Var.of("endpoint"),
				new StatementPattern(Var.of("remoteSubject"), Var.of("remotePredicate"), Var.of("remoteObject")),
				"?remoteSubject ?remotePredicate ?remoteObject .", prefixes, "https://example.com/base/", true);

		TupleFunctionCall tupleFunction = new TupleFunctionCall();
		tupleFunction.setURI("urn:tuple-function");
		tupleFunction.addArgs(Var.of("score"), new ValueConstant(VF.createLiteral(2)));
		tupleFunction.addResultVars(Var.of("quotient"), Var.of("remainder"));
		TupleExpr source = new Union(values, new Union(service, tupleFunction));

		PackedQuery packed = PackedQueryCodec.encode(source);
		TupleExpr materialized = PackedPlanMaterializer.materialize(packed, packed.rootRelId());

		assertEquals(source, materialized);
		Service materializedService = (Service) ((Union) ((Union) materialized).getRightArg()).getLeftArg();
		assertEquals(service.getPrefixDeclarations(), materializedService.getPrefixDeclarations());
		assertEquals(service.getServiceExpressionString(), materializedService.getServiceExpressionString());
		assertEquals(service.getBaseURI(), materializedService.getBaseURI());
		assertEquals(service.getAskQueryString(), materializedService.getAskQueryString());
		assertEquals(service.isSilent(), materializedService.isSilent());
	}

	@Test
	void roundTripsPlannerRelevantNodeMetadataAndPhysicalAnnotations() throws ReflectiveOperationException {
		StatementPattern pattern = new StatementPattern(Var.of("s"), Var.of("p"), Var.of("o"));
		pattern.setVariableScopeChange(true);
		pattern.setResultSizeEstimate(12.5d);
		pattern.setCostEstimate(7.25d);
		pattern.setLongMetricPlanned("plannedLookups", 17L);
		pattern.setDoubleMetricPlanned("plannedSelectivity", 0.125d);
		pattern.setStringMetricPlanned("plannedAccess", "predicate-index");
		Join source = new Join(pattern, new SingletonSet());
		source.setAlgorithm("HashJoinIteration");
		source.setMergeJoin(true);
		source.setCacheable(true);

		PackedQuery packed = PackedQueryCodec.encode(source);
		Join materialized = (Join) PackedPlanMaterializer.materialize(packed, packed.rootRelId());
		StatementPattern materializedPattern = (StatementPattern) materialized.getLeftArg();

		assertTrue(materializedPattern.isVariableScopeChange());
		assertEquals(12.5d, materializedPattern.getResultSizeEstimate());
		assertEquals(7.25d, materializedPattern.getCostEstimate());
		assertEquals(17L, materializedPattern.getLongMetricPlanned("plannedLookups"));
		assertEquals(0.125d, materializedPattern.getDoubleMetricPlanned("plannedSelectivity"));
		assertEquals("predicate-index", materializedPattern.getStringMetricPlanned("plannedAccess"));
		assertEquals("HashJoinIteration", materialized.getAlgorithmName());
		assertTrue(materialized.isMergeJoin());
		Field cacheable = Join.class.getDeclaredField("cacheable");
		cacheable.setAccessible(true);
		assertTrue(cacheable.getBoolean(materialized));
	}

	@Test
	@SuppressWarnings("unchecked")
	void packedHotStateIsMarkedAndHasNoObjectCollectionFields() throws ClassNotFoundException {
		Class<? extends Annotation> marker = (Class<? extends Annotation>) Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed.PackedHotPath");
		for (Class<?> type : new Class<?>[] { PackedBindingFacts.class, PackedBindingSetArena.class,
				PackedCostContext.class, PackedCostEstimate.class, PackedExpressionInterner.class,
				PackedFilterRules.class, PackedIncumbentSearch.class, PackedIntSequenceInterner.class,
				PackedJoinEnumerator.class, PackedLongSubsetTable.class, PackedMaskInterner.class,
				PackedMaskLayout.class, PackedMemo.class, PackedNodeMetadataArena.class, PackedObjectPool.class,
				PackedPhysicalMetadataArena.class, PackedPhysicalPropertyInterner.class, PackedPlanRecipe.class,
				PackedPrimitiveHash.class, PackedQuery.class, PackedQueryView.class, PackedRuleState.class,
				PackedSearchBudget.class, PackedSelectedPlanContextualizer.class, PackedSymbolTable.class,
				PackedWinnerTable.class }) {
			assertTrue(type.isAnnotationPresent(marker), type.getSimpleName());
			for (Field field : type.getDeclaredFields()) {
				assertFalse(TupleExpr.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(java.util.Collection.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(java.util.Map.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(java.util.Optional.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(java.util.Queue.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(java.util.stream.BaseStream.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
				assertFalse(Number.class.isAssignableFrom(field.getType()),
						type.getSimpleName() + "." + field.getName());
			}
		}
	}

	@Test
	void unknownTupleSubtypeFailsBeforeSearchWithOperatorPath() {
		UnsupportedCascadesOperatorException failure = assertThrows(UnsupportedCascadesOperatorException.class,
				() -> PackedQueryCodec.encode(new UnknownTuple(new StatementPattern(Var.of("s"), Var.of("p"),
						Var.of("o")))));

		assertTrue(failure.getMessage().contains(UnknownTuple.class.getName()));
		assertTrue(failure.getMessage().contains("root"));
	}

	private static final class UnknownTuple extends UnaryTupleOperator {

		private static final long serialVersionUID = 1L;

		private UnknownTuple(TupleExpr argument) {
			super(argument);
		}

		@Override
		public <X extends Exception> void visit(QueryModelVisitor<X> visitor) throws X {
			visitor.meetOther(this);
		}
	}
